import React, { memo } from "react";
import { Sparkles, ShieldCheck, Clock, Phone } from "lucide-react";
import { Button } from "./src/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "./src/components/ui/card";

const Section = ({ id, children, className = "" }) => (
  <section id={id} className={`mx-auto w-full max-w-7xl px-6 md:px-10 ${className}`}>{children}</section>
);

const PHONE_TEL = "+37256846555";

const PRICING_PACKAGES = [
  {
    title: "Diagnostika ja veaotsing",
    price: "al 69 €",
    turnaround: "1-2h",
    badge: "Populaarseim",
    description: "OBD/CAN analüüs ja kontrollnimekirja põhine kontroll.",
    includes: [
      "OBD/CAN raport kuni 10 lk",
      "Savestatud mõõtmised ja soovitused",
      "Tasuta visuaalne kontroll",
    ],
  },
  {
    title: "Veermik & pidurid",
    price: "al 149 €",
    turnaround: "samal päeval",
    badge: "Garantiiga",
    description: "Pidurid, amortisaatorid ja veermiku detailid ühe visiidiga.",
    includes: [
      "Reaalaegne kulumimõõtmine",
      "Premium/OE varuosade valik",
      "6-kuuline töögarantii",
    ],
  },
  {
    title: "Detailing ja kaitse",
    price: "al 199 €",
    turnaround: "1 päev",
    badge: "Stuudiopakk",
    description: "Pehme pesu, poleer, kaitse ning salongi värskendus.",
    includes: [
      "Kahe etapi poleer või süvapesu",
      "Velgede ja klaaside kaitse",
      "Järelhoolduse juhend PDF-is",
    ],
  },
];

const PricingSection = memo(() => {
  return (
    <Section id="pricing" className="py-12">
      <Card className="mx-auto max-w-6xl rounded-3xl border-white/40 bg-white/85 shadow-xl backdrop-blur dark:bg-slate-900/70 dark:border-slate-800">
        <CardHeader className="text-center">
          <CardTitle asChild className="text-3xl md:text-4xl font-bold tracking-tight text-slate-900 dark:text-slate-100">
            <h2>Läbipaistvad hinnad ja paketid</h2>
          </CardTitle>
          <p className="mt-3 text-slate-800 dark:text-slate-300">Tüüpilised hinnavahemikud, et teaksid kohe, mis sind ees ootab. Täpse pakkumise saad 5 küsimusega või fotode järgi.</p>
          <div className="mt-4 flex flex-wrap items-center justify-center gap-3 text-xs uppercase tracking-wide text-slate-600 dark:text-slate-400">
            <span className="px-3 py-1 rounded-full bg-slate-100/70 dark:bg-slate-800/70">Tasuta visuaalne kontroll</span>
            <span className="px-3 py-1 rounded-full bg-slate-100/70 dark:bg-slate-800/70">Hinnad sisaldavad käibemaksu</span>
            <span className="px-3 py-1 rounded-full bg-slate-100/70 dark:bg-slate-800/70">6-kuuline garantii</span>
          </div>
        </CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {PRICING_PACKAGES.map((pkg) => (
              <div
                key={pkg.title}
                className="rounded-3xl border border-white/40 bg-white shadow-lg shadow-slate-200/60 p-6 flex flex-col dark:bg-slate-900/70 dark:border-slate-800 dark:shadow-none"
              >
                <div className="flex items-start justify-between gap-3">
                  <h3 className="text-2xl font-semibold text-slate-900 dark:text-slate-100">{pkg.title}</h3>
                  <span className="text-xs font-semibold uppercase tracking-wide text-[#0F62FE] bg-[#0F62FE]/10 rounded-full px-3 py-1">
                    {pkg.badge}
                  </span>
                </div>
                <p className="mt-3 text-3xl font-bold text-slate-900 dark:text-white">{pkg.price}</p>
                <p className="text-sm text-slate-600 dark:text-slate-400">Töö valmib {pkg.turnaround}</p>
                <p className="mt-2 text-sm text-slate-700 dark:text-slate-300">{pkg.description}</p>
                <ul className="mt-4 space-y-2 text-sm text-slate-700 dark:text-slate-200">
                  {pkg.includes.map((item) => (
                    <li key={item} className="flex items-start gap-2">
                      <CheckCircle2 className="h-4 w-4 text-[#0F62FE] mt-0.5" />
                      <span>{item}</span>
                    </li>
                  ))}
                </ul>
                <div className="mt-6 flex flex-col gap-3">
                  <Button
                    asChild
                    className="w-full rounded-xl bg-[#004E92] hover:bg-[#00366A] shadow-[#004E92]/20 shadow-lg"
                  >
                    <a
                      href="#contact-form"
                      className="flex items-center justify-center gap-2"
                    >
                      <Sparkles className="h-4 w-4" />
                      Broneeri aeg
                    </a>
                  </Button>
                  <Button asChild variant="secondary" className="w-full rounded-xl border-slate-200 dark:border-slate-700">
                    <a href={`tel:${PHONE_TEL}`} className="flex items-center justify-center gap-2">
                      <Phone className="h-4 w-4" />
                      Küsi lisainfot
                    </a>
                  </Button>
                </div>
              </div>
            ))}
          </div>
          <div className="mt-8 flex flex-col md:flex-row items-center justify-between gap-4 text-sm text-slate-700 dark:text-slate-300">
            <div className="flex items-center gap-3">
              <ShieldCheck className="h-5 w-5 text-[#0F62FE]" />
              <span>Hinnad sisaldavad kvaliteedikontrolli ja töö üleandmise check-listi.</span>
            </div>
            <div className="flex items-center gap-3">
              <Clock className="h-5 w-5 text-[#0F62FE]" />
              <span>Kiirtöö vajadus? Märgi broneerimisvormis ja tõstame järjekorras esikohale.</span>
            </div>
            <div className="flex items-center gap-3">
              <Phone className="h-5 w-5 text-[#0F62FE]" />
              <a href={`tel:${PHONE_TEL}`} className="font-semibold text-[#0F62FE] hover:underline">
                Hinnapakkumine telefonil {PHONE_TEL}
              </a>
            </div>
          </div>
        </CardContent>
      </Card>
    </Section>
  );
});

PricingSection.displayName = 'PricingSection';

export default PricingSection;
